import{_ as e,o as a,c as o,a2 as l}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"风险 Risk","description":"投资中唯一需要计算的，是永久性损失的风险","frontmatter":{"title":"风险 Risk","description":"投资中唯一需要计算的，是永久性损失的风险"},"headers":[],"relativePath":"02_concepts/risk.md","filePath":"02_concepts/risk.md"}'),r={name:"02_concepts/risk.md"};function h(p,t,u,i,q,s){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="风险-risk" tabindex="-1">风险 Risk <a class="header-anchor" href="#风险-risk" aria-label="Permalink to &quot;风险 Risk&quot;">​</a></h1><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;">**[[/01_letters/1993年/核心总结</td><td style="text-align:left;">1993年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2003年/核心总结</td><td style="text-align:left;">2003年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2007年/核心总结</td><td style="text-align:left;">2007年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2008年/核心总结</td><td style="text-align:left;">2008年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2015年/核心总结</td><td style="text-align:left;">2015年]]**</td></tr></tbody></table><hr><h2 id="重新定义风险" tabindex="-1">重新定义风险 <a class="header-anchor" href="#重新定义风险" aria-label="Permalink to &quot;重新定义风险&quot;">​</a></h2><p>在华尔街，风险通常被定义为&quot;波动性&quot;。<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>对此嗤之以鼻，他认为这是对风险最普遍的误解。</p><blockquote><p>&quot;大多数金融教授都会告诉你，个股的风险是通过其价格相对于整体市场的波动程度来衡量的。他们称之为贝塔（Beta）——一只股票相对于市场的波动程度。波动越大，根据这个理论，风险就越大。这是一个非常整洁的理论。但这有一个致命的缺陷：我们不认为 Beta 是风险的代名词。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2007年致股东信</p></blockquote><p>真正的风险只有一种：<strong>永久性损失本金的可能性</strong>。</p><blockquote><p>&quot;风险的定义是：投资损失金钱的可能性。对我们来说，风险不是一只股票在一年内上涨或下跌了多少——我们不在乎这些。对我们来说，风险是你投资的公司可能在十年内倒闭或严重损害你的永久购买力。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2003年<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>年度股东大会</p></blockquote><h2 id="两个层次的风险" tabindex="-1">两个层次的风险 <a class="header-anchor" href="#两个层次的风险" aria-label="Permalink to &quot;两个层次的风险&quot;">​</a></h2><h3 id="_1-永久性损失的风险-核心风险" tabindex="-1">1. 永久性损失的风险（核心风险） <a class="header-anchor" href="#_1-永久性损失的风险-核心风险" aria-label="Permalink to &quot;1. 永久性损失的风险（核心风险）&quot;">​</a></h3><p>这是<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>最在意的风险。一个企业可能因为竞争失败、行业衰退或管理层失误而走向消亡。一旦发生，投资本金将永久性损失。</p><blockquote><p>&quot;你必须记住，股票市场是一个躁郁症患者，他每天都会给你报价。在大部分时间里，他都会给你一个疯狂的价格——要么太高，要么太低。而真正成功的人，是那些利用他的疯狂，而不是被他牵着鼻子走的人。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><h3 id="_2-暂时性损失的风险-可接受风险" tabindex="-1">2. 暂时性损失的风险（可接受风险） <a class="header-anchor" href="#_2-暂时性损失的风险-可接受风险" aria-label="Permalink to &quot;2. 暂时性损失的风险（可接受风险）&quot;">​</a></h3><p>市场价格会因为各种原因剧烈波动——经济衰退、政策变化、情绪恐慌。这种波动带来的损失是暂时的，不是真正的风险。</p><blockquote><p>&quot;我们喜欢在价格相对于内在价值被低估时购买股票。如果市场某天关闭几年，我们根本不在乎。我们持有的股票价格可能会下跌50%甚至更多。但对我们来说，如果公司本身的基本面没有变化，那只是市场在胡说八道。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2010年</p></blockquote><h2 id="巴菲特如何衡量风险" tabindex="-1"><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>如何衡量风险 <a class="header-anchor" href="#巴菲特如何衡量风险" aria-label="Permalink to &quot;[[巴菲特]]如何衡量风险&quot;">​</a></h2><h3 id="安全边际" tabindex="-1">安全边际 <a class="header-anchor" href="#安全边际" aria-label="Permalink to &quot;安全边际&quot;">​</a></h3><p>安全边际是<a href="/04_people/本·格雷厄姆.html">格雷厄姆</a>传给<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>最重要的投资原则之一，也是他管理风险的核心工具。</p><blockquote><p>&quot;建造一座能承受30吨压力的桥梁，而不是只建一座15吨的。内在价值与价格之间的差异就是你的安全边际。如果你的桥梁设计只能承受15吨，但你只让15吨的车过，你就给自己留了安全边际。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，1997年</p></blockquote><p>安全边际意味着你永远不要为一个&quot;合理&quot;的价格付账——你要等待一个&quot;有吸引力&quot;的价格。这个折扣就是你面对不确定性的保护垫。</p><blockquote><p>&quot;用合理的价格购买优秀的企业，而不是用优秀的价格购买合理的企业。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><p>这句话的深意在于：即使你判断失误，一家企业比预期更早地开始衰落，合理的价格加上安全边际，仍能保护你免受灾难性损失。</p><h3 id="四种永远不会投资的情况" tabindex="-1">四种永远不会投资的情况 <a class="header-anchor" href="#四种永远不会投资的情况" aria-label="Permalink to &quot;四种永远不会投资的情况&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在他的职业生涯中逐步确立了一套风险过滤机制：</p><blockquote><p>&quot;有四种情况我们是绝对不会投资的：第一，我们不理解的业务；第二，没有持久竞争优势的业务；第三，面临剧烈且不可预测的竞争格局的业务；第四，面临严重通货膨胀压力的业务。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><h3 id="集中投资-vs-分散投资" tabindex="-1">集中投资 vs. 分散投资 <a class="header-anchor" href="#集中投资-vs-分散投资" aria-label="Permalink to &quot;集中投资 vs. 分散投资&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>对分散投资持复杂态度：</p><blockquote><p>&quot;如果你知道自己在做什么，分散投资只会降低你的回报，而不是降低你的风险。说分散投资可以降低风险的人，通常是在说&#39;我不懂自己在做什么&#39;。真正懂投资的人，不需要分散。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><p>但他也承认前提是&quot;真正懂&quot;。对于大多数人来说，适度的分散是必要的。</p><blockquote><p>&quot;如果你没有信心对十家企业中的任何一家做出判断，那就不要把你的鸡蛋放在一个篮子里。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><h2 id="杠杆是风险的放大器" tabindex="-1">杠杆是风险的放大器 <a class="header-anchor" href="#杠杆是风险的放大器" aria-label="Permalink to &quot;杠杆是风险的放大器&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>最不原谅的风险来源是杠杆——借钱投资。</p><blockquote><p>&quot;用借来的钱进行投资的人，在市场下跌时会遭受双重打击。他们不仅会因为投资本身而亏损，还会因为杠杆效应而放大损失。而且，他们借款的能力会在最糟糕的时刻消失——因为当所有人都悲观时，债主往往是最悲观的。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2019年致股东信</p></blockquote><p>杠杆在放大收益的同时也放大了风险，而市场的短期波动往往超出任何人的预测。用杠杆投资，实际上是把命运交给了市场在最坏时刻的表现。</p><blockquote><p>&quot;我见过很多聪明人因为杠杆而毁灭。如果你是聪明人，你不需要杠杆；如果你是傻瓜，杠杆只会让你更蠢。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><h2 id="风险管理的核心原则" tabindex="-1">风险管理的核心原则 <a class="header-anchor" href="#风险管理的核心原则" aria-label="Permalink to &quot;风险管理的核心原则&quot;">​</a></h2><h3 id="_1-永远不要亏损" tabindex="-1">1. 永远不要亏损 <a class="header-anchor" href="#_1-永远不要亏损" aria-label="Permalink to &quot;1. 永远不要亏损&quot;">​</a></h3><p>这听起来像是一句废话，但<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的真正含义是：<strong>不要冒永久性损失的风险去追求超额收益</strong>。</p><blockquote><p>&quot;第一条规则：永远不要亏损。第二条规则：永远不要忘记第一条。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><h3 id="_2-用长期视角看风险" tabindex="-1">2. 用长期视角看风险 <a class="header-anchor" href="#_2-用长期视角看风险" aria-label="Permalink to &quot;2. 用长期视角看风险&quot;">​</a></h3><blockquote><p>&quot;如果你不打算持有这只股票十年，那就不要考虑持有它十分钟。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><p>以十年为单位思考时，市场的短期波动几乎可以忽略不计，很多&quot;风险&quot;会在时间的长河中自动消解。</p><h3 id="_3-保持充足的流动性" tabindex="-1">3. 保持充足的流动性 <a class="header-anchor" href="#_3-保持充足的流动性" aria-label="Permalink to &quot;3. 保持充足的流动性&quot;">​</a></h3><blockquote><p>&quot;现金是为王的企业环境中最重要的资产之一。尽管现金没有产生任何回报，但在最坏的环境中，它保护了我们的资产负债表。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2020年致股东信</p></blockquote><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>在2020年疫情期间持有超过1300亿美元的现金和国债，这让他在最需要投资的时候拥有充足的&quot;弹药&quot;。</p><h3 id="_4-远离复杂的金融衍生品" tabindex="-1">4. 远离复杂的金融衍生品 <a class="header-anchor" href="#_4-远离复杂的金融衍生品" aria-label="Permalink to &quot;4. 远离复杂的金融衍生品&quot;">​</a></h3><blockquote><p>&quot;衍生品是大规模杀伤性金融武器，具有潜在的致命危险。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2008年致股东信</p></blockquote><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>曾因为投资金融衍生品而亏损，他后来将这类工具描述为&quot;系统性风险的来源&quot;。</p><h2 id="对普通投资者的启示" tabindex="-1">对普通投资者的启示 <a class="header-anchor" href="#对普通投资者的启示" aria-label="Permalink to &quot;对普通投资者的启示&quot;">​</a></h2><ol><li><strong>把风险定义为永久性损失</strong>——不要被短期波动吓倒，也不要用波动率来衡量风险</li><li><strong>始终留有安全边际</strong>——不要为任何资产付出过高的价格</li><li><strong>远离杠杆</strong>——时间是你的朋友，杠杆是你的敌人</li><li><strong>保持现金储备</strong>——在别人恐惧时有子弹可用</li><li><strong>长期思维</strong>——以十年为单位思考，大幅降低风险感知</li></ol><blockquote><p>&quot;风险来自于不知道自己在做什么。&quot;<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的风险哲学可以归结为一句话：<strong>控制永久性损失的风险，让时间去积累复利。</strong></p><p>他通过安全边际、优质企业、集中投资和远离杠杆这四把钥匙，构建了一套完整的风险管理框架。这套框架不是为了避免所有波动，而是为了在漫长的投资生涯中，<strong>永远不被市场淘汰</strong>。</p><blockquote><p>&quot;活得够久&quot;才是投资中最重要的风险管理。<br> ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>的实践真谛</p></blockquote>',57)])])}const c=e(r,[["render",h]]);export{b as __pageData,c as default};
